import{_ as a,o as s,c as n,a2 as e}from"./chunks/framework.CHSDihme.js";const i="/claude-code-token-free/assets/01-agent-overview.DxZaGVuZ.png",d="/claude-code-token-free/assets/02-agent-types.RtionrS2.png",p="/claude-code-token-free/assets/03-spawn-flow.TCnQ-iA8.png",o="/claude-code-token-free/assets/04-agent-teams.wAMqJVPw.png",q=JSON.parse('{"title":"Claude Code 多 Agent 系统 — 使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"agent/01-usage-guide.md","filePath":"agent/01-usage-guide.md","lastUpdated":1780380166000}'),l={name:"agent/01-usage-guide.md"};function r(h,t,c,g,u,k){return s(),n("div",null,[...t[0]||(t[0]=[e('<h1 id="claude-code-多-agent-系统--使用指南" tabindex="-1">Claude Code 多 Agent 系统 — 使用指南 <a class="header-anchor" href="#claude-code-多-agent-系统--使用指南" aria-label="Permalink to &quot;Claude Code 多 Agent 系统 — 使用指南&quot;">​</a></h1><blockquote><p>让 Claude Code 同时调度多个专业代理，并行处理复杂任务。</p></blockquote><p align="center"><a href="#一什么是多-agent-系统">多 Agent 系统</a> · <a href="#二六种内置-agent">六种内置 Agent</a> · <a href="#三如何生成-agent">如何生成 Agent</a> · <a href="#四后台任务管理">后台任务管理</a> · <a href="#五agent-teams--多代理协作">Agent Teams</a> · <a href="#六自定义-agent">自定义 Agent</a> · <a href="#七权限模式">权限模式</a> · <a href="#八快速参考">快速参考</a></p><p><img src="'+i+'" alt="多 Agent 系统概览"></p><hr><h2 id="一什么是多-agent-系统" tabindex="-1">一、什么是多 Agent 系统？ <a class="header-anchor" href="#一什么是多-agent-系统" aria-label="Permalink to &quot;一、什么是多 Agent 系统？&quot;">​</a></h2><p>Claude Code 的多 Agent 系统是一套<strong>智能任务编排框架</strong>，让主代理能够生成多个专业化的子代理（Subagent），各自独立执行不同的任务，最终将结果汇总给用户。</p><p>核心理念：<strong>把大任务拆分为多个专业小任务，并行执行，提高效率。</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>传统方式</th><th>多 Agent 方式</th></tr></thead><tbody><tr><td>调研 5 个模块的架构</td><td>逐个串行探索</td><td>5 个 Explore agent 并行扫描</td></tr><tr><td>实现 + 测试 + 文档</td><td>顺序完成</td><td>Team 成员各自负责一块</td></tr><tr><td>代码审查</td><td>单线程逐文件看</td><td>多个 reviewer 并行审查</td></tr><tr><td>调试复杂 bug</td><td>一个假设一个假设试</td><td>多个 debugger 并行验证</td></tr></tbody></table><hr><h2 id="二六种内置-agent" tabindex="-1">二、六种内置 Agent <a class="header-anchor" href="#二六种内置-agent" aria-label="Permalink to &quot;二、六种内置 Agent&quot;">​</a></h2><p><img src="'+d+`" alt="六种内置 Agent"></p><p>Claude Code 内置了 6 种专业代理，每种都有特定的工具池和适用场景：</p><h3 id="1-general-purpose通用代理" tabindex="-1">1. general-purpose（通用代理） <a class="header-anchor" href="#1-general-purpose通用代理" aria-label="Permalink to &quot;1. general-purpose（通用代理）&quot;">​</a></h3><p><strong>适用场景</strong>：复杂的多步骤研究、代码搜索、需要完整工具访问的任务。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;调研认证模块&quot;,</span></span>
<span class="line"><span>  prompt: &quot;分析 src/auth/ 下所有文件的认证流程...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;general-purpose&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>工具池</strong>：全部工具（<code>*</code>）</li><li><strong>模型</strong>：继承父代理</li><li><strong>特点</strong>：万能型，不确定用哪个 agent 时选它</li></ul><h3 id="2-explore探索代理" tabindex="-1">2. Explore（探索代理） <a class="header-anchor" href="#2-explore探索代理" aria-label="Permalink to &quot;2. Explore（探索代理）&quot;">​</a></h3><p><strong>适用场景</strong>：快速搜索文件、搜索代码模式、回答代码库结构问题。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;搜索 API 端点&quot;,</span></span>
<span class="line"><span>  prompt: &quot;找到所有 REST API 端点的定义...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;Explore&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>工具池</strong>：只读工具（Glob、Grep、Read、Bash）</li><li><strong>模型</strong>：Haiku（快速低成本）</li><li><strong>特点</strong>：不能修改文件，速度快，适合调研</li></ul><h3 id="3-plan规划代理" tabindex="-1">3. Plan（规划代理） <a class="header-anchor" href="#3-plan规划代理" aria-label="Permalink to &quot;3. Plan（规划代理）&quot;">​</a></h3><p><strong>适用场景</strong>：设计实现方案、分析架构权衡、生成分步计划。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;规划重构方案&quot;,</span></span>
<span class="line"><span>  prompt: &quot;设计将 monolith 拆分为微服务的方案...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;Plan&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>工具池</strong>：只读工具（同 Explore）</li><li><strong>模型</strong>：继承父代理（需要强推理能力）</li><li><strong>特点</strong>：输出结构化计划，包含关键文件和依赖分析</li></ul><h3 id="4-verification验证代理" tabindex="-1">4. verification（验证代理） <a class="header-anchor" href="#4-verification验证代理" aria-label="Permalink to &quot;4. verification（验证代理）&quot;">​</a></h3><p><strong>适用场景</strong>：独立验证实现是否正确，运行测试，边界检查。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;验证登录功能&quot;,</span></span>
<span class="line"><span>  prompt: &quot;验证新实现的登录功能是否正确...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;verification&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>工具池</strong>：只读工具</li><li><strong>模型</strong>：继承父代理</li><li><strong>特点</strong>：始终在后台运行，输出 PASS/FAIL/PARTIAL 判定，红色标识</li></ul><h3 id="5-claude-code-guide指南代理" tabindex="-1">5. claude-code-guide（指南代理） <a class="header-anchor" href="#5-claude-code-guide指南代理" aria-label="Permalink to &quot;5. claude-code-guide（指南代理）&quot;">​</a></h3><p><strong>适用场景</strong>：回答关于 Claude Code、Agent SDK、Claude API 的问题。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;查询 Claude API 用法&quot;,</span></span>
<span class="line"><span>  prompt: &quot;如何使用 tool_use 功能...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;claude-code-guide&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>工具池</strong>：Bash、Read、WebFetch、WebSearch</li><li><strong>模型</strong>：Haiku</li><li><strong>特点</strong>：专注文档查询，dontAsk 权限模式</li></ul><h3 id="6-statusline-setup状态栏配置代理" tabindex="-1">6. statusline-setup（状态栏配置代理） <a class="header-anchor" href="#6-statusline-setup状态栏配置代理" aria-label="Permalink to &quot;6. statusline-setup（状态栏配置代理）&quot;">​</a></h3><p><strong>适用场景</strong>：配置 Claude Code 状态栏显示。</p><ul><li><strong>工具池</strong>：仅 Read + Edit</li><li><strong>模型</strong>：Sonnet</li><li><strong>特点</strong>：高度专业化，范围极小</li></ul><h3 id="agent-类型对比表" tabindex="-1">Agent 类型对比表 <a class="header-anchor" href="#agent-类型对比表" aria-label="Permalink to &quot;Agent 类型对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>读写</th><th>工具池</th><th>模型</th><th>用途</th></tr></thead><tbody><tr><td>general-purpose</td><td>读写</td><td>全部</td><td>继承</td><td>通用任务</td></tr><tr><td>Explore</td><td>只读</td><td>搜索+读取</td><td>Haiku</td><td>快速探索</td></tr><tr><td>Plan</td><td>只读</td><td>搜索+读取</td><td>继承</td><td>架构规划</td></tr><tr><td>verification</td><td>只读</td><td>搜索+读取</td><td>继承</td><td>独立验证</td></tr><tr><td>claude-code-guide</td><td>只读</td><td>搜索+网络</td><td>Haiku</td><td>文档指南</td></tr><tr><td>statusline-setup</td><td>读写</td><td>Read+Edit</td><td>Sonnet</td><td>状态栏配置</td></tr></tbody></table><hr><h2 id="三如何生成-agent" tabindex="-1">三、如何生成 Agent <a class="header-anchor" href="#三如何生成-agent" aria-label="Permalink to &quot;三、如何生成 Agent&quot;">​</a></h2><h3 id="基本参数" tabindex="-1">基本参数 <a class="header-anchor" href="#基本参数" aria-label="Permalink to &quot;基本参数&quot;">​</a></h3><p>Agent 工具接受以下参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>类型</th><th>必需</th><th>说明</th></tr></thead><tbody><tr><td><code>description</code></td><td>string</td><td>是</td><td>3-5 词任务简述</td></tr><tr><td><code>prompt</code></td><td>string</td><td>是</td><td>完整的任务描述</td></tr><tr><td><code>subagent_type</code></td><td>string</td><td>否</td><td>Agent 类型（见上表）</td></tr><tr><td><code>model</code></td><td>string</td><td>否</td><td>模型覆盖：sonnet/opus/haiku</td></tr><tr><td><code>run_in_background</code></td><td>boolean</td><td>否</td><td>是否后台运行</td></tr><tr><td><code>name</code></td><td>string</td><td>否</td><td>命名后可通过 SendMessage 寻址</td></tr><tr><td><code>team_name</code></td><td>string</td><td>否</td><td>加入指定团队</td></tr><tr><td><code>mode</code></td><td>string</td><td>否</td><td>权限模式</td></tr><tr><td><code>isolation</code></td><td>string</td><td>否</td><td>隔离模式：worktree</td></tr></tbody></table><h3 id="前台同步执行默认" tabindex="-1">前台同步执行（默认） <a class="header-anchor" href="#前台同步执行默认" aria-label="Permalink to &quot;前台同步执行（默认）&quot;">​</a></h3><p>最简单的用法，Agent 执行完毕后返回结果：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;分析错误日志&quot;,</span></span>
<span class="line"><span>  prompt: &quot;读取 logs/ 下最近的错误日志，总结常见错误模式&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>主代理会等待子代理完成，然后收到结果继续工作。</p><h3 id="后台异步执行" tabindex="-1">后台异步执行 <a class="header-anchor" href="#后台异步执行" aria-label="Permalink to &quot;后台异步执行&quot;">​</a></h3><p>适合耗时任务，主代理可以继续做其他事情：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;全面代码审查&quot;,</span></span>
<span class="line"><span>  prompt: &quot;审查 src/ 下所有 TypeScript 文件的代码质量...&quot;,</span></span>
<span class="line"><span>  run_in_background: true</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li>Agent 立即返回 <code>async_launched</code> 状态和 taskId</li><li>主代理继续工作，不需要等待</li><li>Agent 完成后自动收到 <code>&lt;task-notification&gt;</code> 通知</li><li>通知包含任务状态、输出文件路径和结果摘要</li></ul><h3 id="并行生成多个-agent" tabindex="-1">并行生成多个 Agent <a class="header-anchor" href="#并行生成多个-agent" aria-label="Permalink to &quot;并行生成多个 Agent&quot;">​</a></h3><p>在一条消息中生成多个独立的 Agent，实现真正的并行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 同时启动 3 个探索 agent</span></span>
<span class="line"><span>Agent({ description: &quot;探索前端&quot;, prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot;, run_in_background: true })</span></span>
<span class="line"><span>Agent({ description: &quot;探索后端&quot;, prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot;, run_in_background: true })</span></span>
<span class="line"><span>Agent({ description: &quot;探索数据库&quot;, prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot;, run_in_background: true })</span></span></code></pre></div><h3 id="worktree-隔离" tabindex="-1">Worktree 隔离 <a class="header-anchor" href="#worktree-隔离" aria-label="Permalink to &quot;Worktree 隔离&quot;">​</a></h3><p>让 Agent 在独立的 git worktree 中工作，不影响主工作区：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;实验性重构&quot;,</span></span>
<span class="line"><span>  prompt: &quot;尝试将模块 X 重构为...&quot;,</span></span>
<span class="line"><span>  isolation: &quot;worktree&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li>自动创建 git worktree（独立分支）</li><li>Agent 在隔离环境中自由修改文件</li><li>完成后如有改动，返回 worktree 路径和分支名</li><li>无改动则自动清理</li></ul><hr><h2 id="四后台任务管理" tabindex="-1">四、后台任务管理 <a class="header-anchor" href="#四后台任务管理" aria-label="Permalink to &quot;四、后台任务管理&quot;">​</a></h2><p><img src="`+p+`" alt="Agent 生成流程"></p><h3 id="任务状态" tabindex="-1">任务状态 <a class="header-anchor" href="#任务状态" aria-label="Permalink to &quot;任务状态&quot;">​</a></h3><p>后台 Agent 有四种状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><code>running</code></td><td>正在执行中</td></tr><tr><td><code>completed</code></td><td>执行成功</td></tr><tr><td><code>failed</code></td><td>执行失败</td></tr><tr><td><code>killed</code></td><td>被手动终止</td></tr></tbody></table><h3 id="进度追踪" tabindex="-1">进度追踪 <a class="header-anchor" href="#进度追踪" aria-label="Permalink to &quot;进度追踪&quot;">​</a></h3><p>后台 Agent 的进度实时更新：</p><ul><li><strong>Token 消耗</strong>：输入/输出 token 计数</li><li><strong>工具使用</strong>：已使用的工具次数</li><li><strong>最近活动</strong>：最近 5 个工具调用描述（循环缓冲区）</li><li><strong>最后活动时间</strong>：用于检测卡住的任务</li></ul><h3 id="完成通知" tabindex="-1">完成通知 <a class="header-anchor" href="#完成通知" aria-label="Permalink to &quot;完成通知&quot;">​</a></h3><p>当后台 Agent 完成时，主代理收到 XML 格式的通知：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-notification</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;abc123&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;completed&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">summary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Agent &quot;探索前端&quot; completed&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">summary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">output-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;~/.claude/temp/.../tasks/abc123.output&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">output-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-notification</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="自动后台化" tabindex="-1">自动后台化 <a class="header-anchor" href="#自动后台化" aria-label="Permalink to &quot;自动后台化&quot;">​</a></h3><p>当 <code>tengu_auto_background_agents</code> 特性开启时，前台 Agent 运行超过 <strong>120 秒</strong>会自动转为后台执行，释放主代理继续工作。</p><hr><h2 id="五agent-teams--多代理协作" tabindex="-1">五、Agent Teams — 多代理协作 <a class="header-anchor" href="#五agent-teams--多代理协作" aria-label="Permalink to &quot;五、Agent Teams — 多代理协作&quot;">​</a></h2><p><img src="`+o+`" alt="Agent Teams 协作"></p><p>Agent Teams 是更高级的多代理协作模式，多个代理以团队形式工作，通过消息通信协调任务。</p><h3 id="创建团队" tabindex="-1">创建团队 <a class="header-anchor" href="#创建团队" aria-label="Permalink to &quot;创建团队&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TeamCreate({</span></span>
<span class="line"><span>  team_name: &quot;feature-team&quot;,</span></span>
<span class="line"><span>  description: &quot;开发用户认证功能&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>团队创建后：</p><ul><li>生成团队配置文件：<code>~/.claude/teams/{team_name}/config.json</code></li><li>创建共享任务目录：<code>~/.claude/tasks/{team_name}/</code></li><li>当前代理自动成为 <strong>Team Lead</strong>（团队负责人）</li></ul><h3 id="添加团队成员" tabindex="-1">添加团队成员 <a class="header-anchor" href="#添加团队成员" aria-label="Permalink to &quot;添加团队成员&quot;">​</a></h3><p>通过 Agent 工具指定 <code>name</code> 和 <code>team_name</code> 生成队友：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;前端开发&quot;,</span></span>
<span class="line"><span>  prompt: &quot;负责实现登录页面的 React 组件...&quot;,</span></span>
<span class="line"><span>  name: &quot;frontend-dev&quot;,</span></span>
<span class="line"><span>  team_name: &quot;feature-team&quot;</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;后端开发&quot;,</span></span>
<span class="line"><span>  prompt: &quot;负责实现认证 API 端点...&quot;,</span></span>
<span class="line"><span>  name: &quot;backend-dev&quot;,</span></span>
<span class="line"><span>  team_name: &quot;feature-team&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><h3 id="队友通信" tabindex="-1">队友通信 <a class="header-anchor" href="#队友通信" aria-label="Permalink to &quot;队友通信&quot;">​</a></h3><p>通过 SendMessage 工具发送消息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 发送给特定队友</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;frontend-dev&quot;,</span></span>
<span class="line"><span>  message: &quot;API 接口已就绪，格式是...&quot;,</span></span>
<span class="line"><span>  summary: &quot;通知 API 接口格式&quot;</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 广播给所有队友</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;*&quot;,</span></span>
<span class="line"><span>  message: &quot;大家暂停，需求变更了...&quot;,</span></span>
<span class="line"><span>  summary: &quot;广播需求变更&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><h3 id="关停协调" tabindex="-1">关停协调 <a class="header-anchor" href="#关停协调" aria-label="Permalink to &quot;关停协调&quot;">​</a></h3><p>当任务完成后，Team Lead 请求队友关停：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 1. 发送关停请求</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;frontend-dev&quot;,</span></span>
<span class="line"><span>  message: { type: &quot;shutdown_request&quot;, reason: &quot;任务已完成&quot; }</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 2. 队友回复批准</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;team-lead&quot;,</span></span>
<span class="line"><span>  message: { type: &quot;shutdown_response&quot;, request_id: &quot;...&quot;, approve: true }</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 3. 所有队友关停后，清理团队</span></span>
<span class="line"><span>TeamDelete()</span></span></code></pre></div><h3 id="执行后端" tabindex="-1">执行后端 <a class="header-anchor" href="#执行后端" aria-label="Permalink to &quot;执行后端&quot;">​</a></h3><p>Agent Teams 支持两种执行后端：</p><table tabindex="0"><thead><tr><th>后端</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>in-process</strong></td><td>同进程运行，AsyncLocalStorage 隔离</td><td>默认模式，轻量高效</td></tr><tr><td><strong>tmux</strong></td><td>独立 tmux pane 运行</td><td>需要独立终端视图</td></tr><tr><td><strong>iTerm2</strong></td><td>独立 iTerm2 窗口运行</td><td>macOS iTerm2 用户</td></tr></tbody></table><hr><h2 id="六自定义-agent" tabindex="-1">六、自定义 Agent <a class="header-anchor" href="#六自定义-agent" aria-label="Permalink to &quot;六、自定义 Agent&quot;">​</a></h2><p>除了内置 Agent，你还可以创建自己的专业代理。</p><h3 id="定义格式" tabindex="-1">定义格式 <a class="header-anchor" href="#定义格式" aria-label="Permalink to &quot;定义格式&quot;">​</a></h3><p>在 <code>.claude/agents/</code> 目录下创建 <code>.md</code> 文件：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name: code-reviewer</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">description: 专业代码审查代理</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tools:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Read</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Grep</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Glob</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Bash</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model: sonnet</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">permissionMode: dontAsk</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">maxTurns: 10</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">你是一个专业的代码审查员。请检查以下方面：</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 代码质量和可读性</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 潜在的安全漏洞</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 性能问题</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 最佳实践遵循</span></span></code></pre></div><h3 id="可配置字段" tabindex="-1">可配置字段 <a class="header-anchor" href="#可配置字段" aria-label="Permalink to &quot;可配置字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>Agent 类型名称</td></tr><tr><td><code>description</code></td><td>string</td><td>何时使用的说明</td></tr><tr><td><code>tools</code></td><td>string[]</td><td>允许的工具列表（<code>[&#39;*&#39;]</code> 表示全部）</td></tr><tr><td><code>disallowedTools</code></td><td>string[]</td><td>禁止的工具列表</td></tr><tr><td><code>model</code></td><td>string</td><td>使用的模型（sonnet/opus/haiku/inherit）</td></tr><tr><td><code>permissionMode</code></td><td>string</td><td>权限模式</td></tr><tr><td><code>maxTurns</code></td><td>number</td><td>最大对话轮数</td></tr><tr><td><code>mcpServers</code></td><td>object[]</td><td>需要的 MCP 服务器</td></tr><tr><td><code>hooks</code></td><td>object</td><td>Agent 特定的钩子</td></tr><tr><td><code>skills</code></td><td>string[]</td><td>可使用的技能</td></tr><tr><td><code>memory</code></td><td>string</td><td>记忆作用域（user/project/local）</td></tr><tr><td><code>isolation</code></td><td>string</td><td>隔离模式（worktree/remote）</td></tr><tr><td><code>background</code></td><td>boolean</td><td>是否默认后台运行</td></tr></tbody></table><h3 id="加载优先级" tabindex="-1">加载优先级 <a class="header-anchor" href="#加载优先级" aria-label="Permalink to &quot;加载优先级&quot;">​</a></h3><p>自定义 Agent 的加载遵循优先级：</p><ol><li><strong>内置 Agent</strong>（built-in）— 系统预定义</li><li><strong>插件 Agent</strong>（plugin）— 通过插件注册</li><li><strong>用户 Agent</strong>（user）— <code>~/.claude/agents/</code></li><li><strong>项目 Agent</strong>（project）— <code>.claude/agents/</code>（项目级）</li><li><strong>标记 Agent</strong>（flag）— 通过 API 注册</li><li><strong>策略 Agent</strong>（policy）— 组织策略</li></ol><p>同名 Agent 按优先级覆盖。</p><hr><h2 id="七权限模式" tabindex="-1">七、权限模式 <a class="header-anchor" href="#七权限模式" aria-label="Permalink to &quot;七、权限模式&quot;">​</a></h2><p>每个 Agent 可以设置不同的权限模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td><code>default</code></td><td>正常权限请求，需要用户确认</td></tr><tr><td><code>plan</code></td><td>所有操作需要显式审批</td></tr><tr><td><code>acceptEdits</code></td><td>自动接受文件编辑，其他操作需确认</td></tr><tr><td><code>bypassPermissions</code></td><td>跳过所有权限检查</td></tr><tr><td><code>dontAsk</code></td><td>拒绝所有未预批准的操作</td></tr><tr><td><code>auto</code></td><td>AI 驱动的权限分类（仅 Ant 内部）</td></tr><tr><td><code>bubble</code></td><td>权限提示冒泡到父代理终端</td></tr></tbody></table><hr><h2 id="八快速参考" tabindex="-1">八、快速参考 <a class="header-anchor" href="#八快速参考" aria-label="Permalink to &quot;八、快速参考&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td>生成子代理</td><td><code>Agent({ prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot; })</code></td></tr><tr><td>后台运行</td><td><code>Agent({ ..., run_in_background: true })</code></td></tr><tr><td>并行生成</td><td>单条消息中发送多个 Agent 调用</td></tr><tr><td>Worktree 隔离</td><td><code>Agent({ ..., isolation: &quot;worktree&quot; })</code></td></tr><tr><td>创建团队</td><td><code>TeamCreate({ team_name: &quot;...&quot; })</code></td></tr><tr><td>发送消息</td><td><code>SendMessage({ to: &quot;name&quot;, message: &quot;...&quot; })</code></td></tr><tr><td>广播消息</td><td><code>SendMessage({ to: &quot;*&quot;, message: &quot;...&quot; })</code></td></tr><tr><td>请求关停</td><td><code>SendMessage({ to: &quot;name&quot;, message: { type: &quot;shutdown_request&quot; } })</code></td></tr><tr><td>删除团队</td><td><code>TeamDelete()</code></td></tr><tr><td>自定义 Agent</td><td>在 <code>.claude/agents/*.md</code> 创建定义文件</td></tr><tr><td>指定模型</td><td><code>Agent({ ..., model: &quot;haiku&quot; })</code></td></tr><tr><td>命名 Agent</td><td><code>Agent({ ..., name: &quot;researcher&quot; })</code></td></tr></tbody></table>`,111)])])}const m=a(l,[["render",r]]);export{q as __pageData,m as default};
